100	  /* ---------- Layout ---------- */
101	  .layout { display: grid; grid-template-columns: 260px 1fr; min-height: 100vh; max-width: 1200px; margin: 0 auto; }
102	
103	  /* ---------- Sidebar ---------- */
104	  aside {
