126	  main { padding: 40px 56px 80px; max-width: 860px; }
127	
128	  /* ---------- Document header ---------- */
129	  .doc-head { margin-bottom: 40px; }
130	  .breadcrumbs { font-size: 13.5px; color: var(--muted); margin-bottom: 16px; }
